module RefModule (
    input [15:0] data_in,
    output reg [3:0] ones_count
);

    integer i;
    reg [15:0] final_sig;

    always @ (data_in) begin
        final_sig = data_in;
        ones_count = 0;
        for (i = 0; i < 16; i = i + 1) begin
            if (final_sig[0] == 1'b1) begin
                ones_count = ones_count + 1;
            end
            final_sig = final_sig >> 1;
        end
    end

endmodule
